use super::super::super::{render::is_windows_path, DeploymentManifest};
use super::super::quote::sh_literal;

pub(in crate::private_network) fn render_unix_preflight_script(
    manifest: &DeploymentManifest,
) -> String {
    let mut text = format!(
        "#!/usr/bin/env sh\nset -eu\n\n# Generated by NeoNexus for {} / magic {}.\ncd \"$(dirname \"$0\")\"\nfailures=0\n\nfail() {{\n  echo \"FAIL: $1\"\n  failures=1\n}}\n\nok() {{\n  echo \"OK: $1\"\n}}\n\nwarn() {{\n  echo \"WARN: $1\"\n}}\n\ncheck_file() {{\n  label=\"$1\"\n  path=\"$2\"\n  if [ -f \"$path\" ]; then\n    ok \"$label exists\"\n  else\n    fail \"$label missing: $path\"\n  fi\n}}\n\ncheck_sha256() {{\n  label=\"$1\"\n  path=\"$2\"\n  expected=\"$3\"\n  if [ ! -f \"$path\" ]; then\n    fail \"$label sha256 skipped; file missing: $path\"\n    return 0\n  fi\n  actual=\"\"\n  if command -v sha256sum >/dev/null 2>&1; then\n    actual=\"$(sha256sum \"$path\" | awk '{{print $1}}')\"\n  elif command -v shasum >/dev/null 2>&1; then\n    actual=\"$(shasum -a 256 \"$path\" | awk '{{print $1}}')\"\n  elif command -v openssl >/dev/null 2>&1; then\n    actual=\"$(openssl dgst -sha256 \"$path\" | awk '{{print $NF}}')\"\n  else\n    warn \"skipping $label sha256; install sha256sum, shasum, or openssl\"\n    return 0\n  fi\n  actual=\"$(printf '%s' \"$actual\" | tr 'A-F' 'a-f')\"\n  expected=\"$(printf '%s' \"$expected\" | tr 'A-F' 'a-f')\"\n  if [ \"$actual\" = \"$expected\" ]; then\n    ok \"$label sha256 matches\"\n  else\n    fail \"$label sha256 mismatch: expected $expected got $actual\"\n  fi\n}}\n\ncheck_dir() {{\n  label=\"$1\"\n  path=\"$2\"\n  if [ -d \"$path\" ]; then\n    ok \"$label exists\"\n  else\n    fail \"$label missing: $path\"\n  fi\n}}\n\ncheck_pid() {{\n  name=\"$1\"\n  workdir=\"$2\"\n  pid_file=\"$workdir/$name.pid\"\n  if [ ! -f \"$pid_file\" ]; then\n    ok \"$name has no active PID file\"\n    return 0\n  fi\n  pid=\"$(cat \"$pid_file\")\"\n  if kill -0 \"$pid\" 2>/dev/null; then\n    fail \"$name already appears to be running with pid $pid\"\n  else\n    warn \"$name has a stale PID file: $pid_file\"\n  fi\n}}\n\ncheck_port() {{\n  label=\"$1\"\n  port=\"$2\"\n  if command -v nc >/dev/null 2>&1; then\n    if nc -z 127.0.0.1 \"$port\" >/dev/null 2>&1; then\n      fail \"$label port $port is already listening on 127.0.0.1\"\n    else\n      ok \"$label port $port is free\"\n    fi\n  elif command -v lsof >/dev/null 2>&1; then\n    if lsof -nP -iTCP:\"$port\" -sTCP:LISTEN >/dev/null 2>&1; then\n      fail \"$label port $port is already listening\"\n    else\n      ok \"$label port $port is free\"\n    fi\n  else\n    warn \"skipping $label port $port check; install nc or lsof\"\n  fi\n}}\n\ncheck_signer_endpoint() {{\n  label=\"$1\"\n  endpoint=\"$2\"\n  timeout=\"${{NEONEXUS_SIGNER_TIMEOUT_SECONDS:-3}}\"\n  if command -v curl >/dev/null 2>&1; then\n    if curl -sS -m \"$timeout\" -o /dev/null \"$endpoint\" >/dev/null 2>&1; then\n      ok \"$label endpoint reachable\"\n    else\n      fail \"$label endpoint unreachable: $endpoint\"\n    fi\n  else\n    warn \"curl not found; skipping $label endpoint check\"\n  fi\n}}\n\ncheck_signer_command() {{\n  label=\"$1\"\n  binary=\"$2\"\n  if [ -z \"$binary\" ]; then\n    fail \"$label sidecar binary missing\"\n    return 0\n  fi\n  case \"$binary\" in\n    */*)\n      if [ -f \"$binary\" ]; then\n        ok \"$label sidecar binary exists\"\n      else\n        fail \"$label sidecar binary missing: $binary\"\n      fi\n      ;;\n    *)\n      if command -v \"$binary\" >/dev/null 2>&1; then\n        ok \"$label sidecar binary is on PATH\"\n      else\n        fail \"$label sidecar binary not found on PATH: $binary\"\n      fi\n      ;;\n  esac\n}}\n\n",
        manifest.runtime, manifest.network_magic
    );
    for node in &manifest.nodes {
        text.push_str(&format!(
            "check_file {} {}\ncheck_file {} {}\ncheck_sha256 {} {} {}\ncheck_dir {} {}\ncheck_pid {} {}\ncheck_port {} {}\ncheck_port {} {}\n",
            sh_literal(&format!("{} binary", node.name)),
            sh_literal(&node.binary_path),
            sh_literal(&format!("{} config", node.name)),
            sh_literal(&node.config_path),
            sh_literal(&format!("{} config", node.name)),
            sh_literal(&node.config_path),
            sh_literal(&node.config_sha256),
            sh_literal(&format!("{} workdir", node.name)),
            sh_literal(&node.working_dir),
            sh_literal(&node.name),
            sh_literal(&node.working_dir),
            sh_literal(&format!("{} RPC", node.name)),
            node.rpc_port,
            sh_literal(&format!("{} P2P", node.name)),
            node.p2p_port
        ));
        if let Some(ws_port) = node.ws_port {
            text.push_str(&format!(
                "check_port {} {}\n",
                sh_literal(&format!("{} WS", node.name)),
                ws_port
            ));
        }
        text.push('\n');
    }
    append_unix_signer_preflight(&mut text, manifest);
    text.push_str(
        "if [ \"$failures\" -ne 0 ]; then\n  echo \"Preflight failed\"\n  exit 1\nfi\n\necho \"Preflight passed\"\n",
    );
    text
}

fn append_unix_signer_preflight(text: &mut String, manifest: &DeploymentManifest) {
    if manifest.committee.signers.is_empty() {
        return;
    }
    text.push_str("# Committee signer references\n");
    for signer in &manifest.committee.signers {
        if let Some(plan) = &signer.signer_command_plan {
            text.push_str(&format!(
                "check_signer_command {} {}\n",
                sh_literal(&signer.label),
                sh_literal(&plan.binary)
            ));
        }
        if let Some(wallet_path) = &signer.wallet_path {
            if is_windows_path(wallet_path) {
                text.push_str(&format!(
                    "warn {}\n",
                    sh_literal(&format!(
                        "{} wallet path is Windows-style; skipping on Unix: {wallet_path}",
                        signer.label
                    ))
                ));
            } else {
                text.push_str(&format!(
                    "check_file {} {}\n",
                    sh_literal(&format!("{} wallet", signer.label)),
                    sh_literal(wallet_path)
                ));
            }
        }
        if let Some(endpoint) = &signer.signer_endpoint {
            if signer.signer_command_plan.is_some() {
                text.push_str(&format!(
                    "warn {}\n",
                    sh_literal(&format!(
                        "{} endpoint will be checked after sidecar start: {endpoint}",
                        signer.label
                    ))
                ));
            } else {
                text.push_str(&format!(
                    "check_signer_endpoint {} {}\n",
                    sh_literal(&signer.label),
                    sh_literal(endpoint)
                ));
            }
        }
    }
    text.push('\n');
}
